public void postRun()
{
    super();
    ETG_InventFairValueContract contract = this.dataContractObject() as ETG_InventFairValueContract;
    // Register the override method for the lookup
    vertical.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETG_InventFairValueUIBuilder, verticalLookup), this);
    // Register the override method for the lookup
    subVertical.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETG_InventFairValueUIBuilder, subVerticalLookup), this);
    // Register the override method for the lookup
    commodity.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETG_InventFairValueUIBuilder, commodityLookup), this);
    // Register the override method for the lookup
    SubCommodity.registerOverrideMethod(methodStr(FormStringControl, lookup), methodStr(ETG_InventFairValueUIBuilder, SubCommodityLookup), this);
}

public void verticalLookup(FormStringControl _control)
{
    SysTableLookup       sysTableLookup = SysTableLookup::newParameters(tableNum(InventTable), _control);
    Query                query;
    QueryBuildDataSource qbds;
    QueryBuildRange      qbr;

    query = new Query();
    qbds = query.addDataSource(tableNum(InventTable));
    // Add a range to exclude empty values
    SysQuery::findOrCreateRange(qbds, fieldNum(InventTable, ETGVertical)).value(SysQuery::valueNotEmptyString());

    qbds.addGroupByField(fieldNum(InventTable,ETGVertical));
    sysTableLookup.parmUseLookupValue(false);
    sysTableLookup.addLookupfield(fieldNum(InventTable, ETGVertical));

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();
}

